/// <summary>
/// This method enables/ disables Credit and Debit note for french and portuguese on LedgerJournalTrans
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataSourceEventHandler(formDataSourceStr(LedgerJournalTransDaily, LedgerJournalTrans), FormDataSourceEventType::Activated)]
public static void LedgerJournalTrans_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    FormRun                         formrun = sender.formRun();
    FormDataSource                  LedgerJournalTrans_Ds = sender as FormDataSource;
    LedgerJournalTrans              ledgerJournalTrans = LedgerJournalTrans_Ds.cursor();
    FormControl                     etgDebitNote,etgCreditNote, etgCreditNoteFrench, etgCreditNotePortugese, etgdebitNoteFr, etgdebitNotePl;
    etgCreditNote          =        formrun.design().controlName(formControlStr(LedgerJournalTransDaily, ETGCreditNoteReport));
    etgdebitNote           =        formrun.design().controlName(formControlStr(LedgerJournalTransDaily, ETGDebitNoteReport));

    etgCreditNote.enabled(LedgerJournalTrans.AmountCurCredit);
    etgdebitNote.enabled(LedgerJournalTrans.AmountCurDebit);

    etgCreditNoteFrench    =        formrun.design().controlName(formControlStr(LedgerJournalTransDaily, ETGCreditNoteReportFrench));
    etgCreditNotePortugese =        formrun.design().controlName(formControlStr(LedgerJournalTransDaily, ETGCreditNoteReportPortugese));
    etgdebitNoteFr         =        formrun.design().controlName(formControlStr(LedgerJournalTransDaily, ETGDebitNoteReportFrench));
    etgdebitNotePl         =        formrun.design().controlName(formControlStr(LedgerJournalTransDaily, ETGDebitNoteReportPortuguese));

    etgCreditNoteFrench.enabled(LedgerJournalTrans.AmountCurCredit);
    etgdebitNoteFr.enabled(LedgerJournalTrans.AmountCurDebit);
    etgCreditNotePortugese.enabled(LedgerJournalTrans.AmountCurCredit);
    etgdebitNotePl.enabled(LedgerJournalTrans.AmountCurDebit);
}

/// <summary>
/// This method validates enabling and disabling of credit/ debit note
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataSourceEventHandler(formDataSourceStr(LedgerJournalTransDaily, LedgerJournalTrans), FormDataSourceEventType::ValidatingWrite)]
public static void LedgerJournalTrans_OnValidatingWrite(FormDataSource sender, FormDataSourceEventArgs e)
{
    FormRun                 formrun = sender.formRun();
    FormDataSource          LedgerJournalTrans_Ds = sender as FormDataSource;
    LedgerJournalTrans      ledgerJournalTrans = LedgerJournalTrans_Ds.cursor();
    FormControl             etgDebitNote,etgCreditNote, etgCreditNoteFrench, etgCreditNotePortugese, etgdebitNoteFr, etgdebitNotePl;

    etgCreditNote = formrun.design().controlName(formControlStr(LedgerJournalTransDaily, ETGCreditNoteReport));
    etgdebitNote  = formrun.design().controlName(formControlStr(LedgerJournalTransDaily, ETGDebitNoteReport));

    etgCreditNote.enabled(LedgerJournalTrans.AmountCurCredit);
    etgdebitNote.enabled(LedgerJournalTrans.AmountCurDebit);

    etgCreditNoteFrench    =        formrun.design().controlName(formControlStr(LedgerJournalTransDaily, ETGCreditNoteReportFrench));
    etgCreditNotePortugese =        formrun.design().controlName(formControlStr(LedgerJournalTransDaily, ETGCreditNoteReportPortugese));
    etgdebitNoteFr         =        formrun.design().controlName(formControlStr(LedgerJournalTransDaily, ETGDebitNoteReportFrench));
    etgdebitNotePl         =        formrun.design().controlName(formControlStr(LedgerJournalTransDaily, ETGDebitNoteReportPortuguese));

    etgCreditNoteFrench.enabled(LedgerJournalTrans.AmountCurCredit);
    etgdebitNoteFr.enabled(LedgerJournalTrans.AmountCurDebit);
    etgCreditNotePortugese.enabled(LedgerJournalTrans.AmountCurCredit);
    etgdebitNotePl.enabled(LedgerJournalTrans.AmountCurDebit);
}

//// <summary>
/// This method enables/ disables Credit and Debit note for french and portuguese on LedgerJournalTable
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataSourceEventHandler(formDataSourceStr(LedgerJournalTable, LedgerJournalTable), FormDataSourceEventType::Activated)]
public static void LedgerJournalTable_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    FormRun                      formrun = sender.formRun();
    FormDataSource               LedgerJournalTable_Ds = sender as FormDataSource;
    LedgerJournalTable           ledgerJournalTable = LedgerJournalTable_Ds.cursor();
    LedgerJournalTrans           ledgerJournalTrans;
    FormControl                  etgDebitNote,etgCreditNote, etgCreditNoteFrench, etgCreditNotePortugese, etgdebitNoteFr, etgdebitNotePl;
    etgCreditNote    =           formrun.design().controlName(formControlStr(LedgerJournalTable, ETGCreditNoteReport));
    etgdebitNote     =           formrun.design().controlName(formControlStr(LedgerJournalTable, ETGDebitNoteReport));


    select firstonly ledgerJournalTrans
        where ledgerJournalTrans.JournalNum == ledgerJournalTable.JournalNum;

    etgCreditNote.enabled(ledgerJournalTrans.AmountCurCredit);
    etgdebitNote.enabled(ledgerJournalTrans.AmountCurDebit);


    etgCreditNoteFrench    = formrun.design().controlName(formControlStr(LedgerJournalTable, ETGCreditNoteReportFrench));
    etgCreditNotePortugese = formrun.design().controlName(formControlStr(LedgerJournalTable, ETGCreditNoteReportPortugese));
    etgdebitNoteFr         = formrun.design().controlName(formControlStr(LedgerJournalTable, ETGDebitNoteReportPortuguese));
    etgdebitNotePl         = formrun.design().controlName(formControlStr(LedgerJournalTable,ETGDebitNoteReportFrench));


    etgCreditNoteFrench.enabled(LedgerJournalTrans.AmountCurCredit);
    etgdebitNoteFr.enabled(LedgerJournalTrans.AmountCurDebit);
    etgCreditNotePortugese.enabled(LedgerJournalTrans.AmountCurCredit);
    etgdebitNotePl.enabled(LedgerJournalTrans.AmountCurDebit);

}

/// <summary>
/// NEW HANDLER: Restricts currency code to USD and makes it uneditable for company o001
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataSourceEventHandler(formDataSourceStr(LedgerJournalTransDaily, LedgerJournalTrans), FormDataSourceEventType::Activated)]
public static void LedgerJournalTrans_Currency_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    FormRun             formRun = sender.formRun();
    LedgerJournalTrans  ledgerJournalTrans = sender.cursor();
    FormControl         currencyCodeControl = formRun.design().controlName(formControlStr(LedgerJournalTransDaily, LedgerJournalTrans_CurrencyCode));

    if (curExt() == 'y002')
    {
        // Set currency to USD if it isn't already
        if (ledgerJournalTrans.CurrencyCode != 'USD')
        {
            ledgerJournalTrans.CurrencyCode = 'USD';
        }

        // Disable the control
        if (currencyCodeControl)
        {
            currencyCodeControl.allowEdit(false);
        }
    }
    else
    {
        // Ensure control is enabled for other companies
        if (currencyCodeControl)
        {
            currencyCodeControl.allowEdit(true);
        }
    }


}

[FormDataSourceEventHandler(formDataSourceStr(LedgerJournalTransDaily, LedgerJournalTrans), FormDataSourceEventType::Activated)]
public static void LedgerJournalTrans_Payment_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    FormRun formRun = sender.formRun();


    FormStringControl paymentControl = formRun.control(formRun.controlId("LedgerJournalTrans_Payment")) as FormStringControl;


    if (paymentControl)
    {
        if (curExt() != 'y002')
        {
            paymentControl.mandatory(true);
        }
        else
        {
            // Explicitly set to false for 'o001' to override any default behavior
            paymentControl.mandatory(false);
        }
    }
}
